Second test is a connection with {color:#d04437}readPreference class{color} with {color:#d04437}nearest{color} and {color:#d04437}tags{color} - {color:#d04437}continent: europe{color}


{code:javascript}
/*
 cfg = rs.conf();
 cfg.members[0].tags.continent = 'america'; // primary    - host = mongo1
 cfg.members[1].tags.continent = 'europe';  // secondary  - host = mongo2
 cfg.members[2].tags.continent = 'africa';  // secondary  - host = mongo3
 rs.reconfig(cfg);
 */

const mongodb = require('mongodb'),
    async = require('async'),
    MongoClient = mongodb.MongoClient,
    ReadPreference = mongodb.ReadPreference;


const
    MAP = {
